diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..cc81e57c2be1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -6821,6 +6821,7 @@ static Instruction *foldReductionIdiom(ICmpInst &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   bool Changed = false;
   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -6849,8 +6850,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
       if (Value *V = dyn_castNegVal(SelectTrue)) {
         if (V == SelectFalse)
           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
-      }
-      else if (Value *V = dyn_castNegVal(SelectFalse)) {
+      } else if (Value *V = dyn_castNegVal(SelectFalse)) {
         if (V == SelectTrue)
           return CmpInst::Create(Instruction::ICmp, I.getPredicate(), V, Op1);
       }
@@ -6970,18 +6970,18 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   //   %sel = select i1 %cond, i1 %cmp, i1 false
   // This handles similar cases to transform.
   {
-    Value *Cond, *A, *B, *C, *D;
+    Value *Cond, *A, *B, *C2, *D;
     if (match(Op0, m_Select(m_Value(Cond), m_Value(A), m_Value(B))) &&
-        match(Op1, m_Select(m_Specific(Cond), m_Value(C), m_Value(D))) &&
+        match(Op1, m_Select(m_Specific(Cond), m_Value(C2), m_Value(D))) &&
         (Op0->hasOneUse() || Op1->hasOneUse())) {
       // Check whether comparison of TrueValues can be simplified
-      if (Value *Res = simplifyICmpInst(Pred, A, C, SQ)) {
+      if (Value *Res = simplifyICmpInst(Pred, A, C2, SQ)) {
         Value *NewICMP = Builder.CreateICmp(Pred, B, D);
         return SelectInst::Create(Cond, Res, NewICMP);
       }
       // Check whether comparison of FalseValues can be simplified
       if (Value *Res = simplifyICmpInst(Pred, B, D, SQ)) {
-        Value *NewICMP = Builder.CreateICmp(Pred, A, C);
+        Value *NewICMP = Builder.CreateICmp(Pred, A, C2);
         return SelectInst::Create(Cond, NewICMP, Res);
       }
     }
@@ -7021,14 +7021,23 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {

     // ~X < ~Y --> Y < X
     // ~X < C -->  X > ~C
+    // ( ~X ^ Y ) Pred ~X  -->  (X ^ Y) swap(Pred) X
+    if (match(Op1, m_Not(m_Value(Y)))) {
+      Value *Z;
+      if (match(Op0, m_Xor(m_Not(m_Specific(Y)), m_Value(Z))) ||
+          match(Op0, m_Xor(m_Value(Z), m_Not(m_Specific(Y))))) {
+        Value *NewXor = Builder.CreateXor(Y, Z);
+        return new ICmpInst(I.getSwappedPredicate(), NewXor, Y);
+      }
+    }
     if (match(Op0, m_Not(m_Value(X)))) {
       if (match(Op1, m_Not(m_Value(Y))))
         return new ICmpInst(I.getPredicate(), Y, X);

-      const APInt *C;
-      if (match(Op1, m_APInt(C)))
+      const APInt *C2;
+      if (match(Op1, m_APInt(C2)))
         return new ICmpInst(I.getSwappedPredicate(), X,
-                            ConstantInt::get(Op1->getType(), ~(*C)));
+                            ConstantInt::get(Op1->getType(), ~(*C2)));
     }

     Instruction *AddI = nullptr;
@@ -7108,15 +7117,15 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
           return ExtractValueInst::Create(ACXI, 1);

   {
-    Value *X;
-    const APInt *C;
+    Value *X2;
+    const APInt *C2;
     // icmp X+Cst, X
-    if (match(Op0, m_Add(m_Value(X), m_APInt(C))) && Op1 == X)
-      return foldICmpAddOpConst(X, *C, I.getPredicate());
+    if (match(Op0, m_Add(m_Value(X2), m_APInt(C2))) && Op1 == X2)
+      return foldICmpAddOpConst(X2, *C2, I.getPredicate());

     // icmp X, X+Cst
-    if (match(Op1, m_Add(m_Value(X), m_APInt(C))) && Op0 == X)
-      return foldICmpAddOpConst(X, *C, I.getSwappedPredicate());
+    if (match(Op1, m_Add(m_Value(X2), m_APInt(C2))) && Op0 == X2)
+      return foldICmpAddOpConst(X2, *C2, I.getSwappedPredicate());
   }

   if (Instruction *Res = foldICmpWithHighBitMask(I, Builder))
@@ -7135,6 +7144,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Fold fcmp ([us]itofp x, cst) if possible.
 Instruction *InstCombinerImpl::foldFCmpIntToFPConst(FCmpInst &I,
                                                     Instruction *LHSI,

log.source_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %xor1 = xor i32 %y, -1
  %xor2 = xor i32 %xor1, %x
  %r = icmp sle i32 %xor2, %xor1
  ret i1 %r
}

log.expect_optimized_program:
define i1 @test_sle_xor(i32 %x, i32 %y) {
  %1 = xor i32 %y, %x
  %r = icmp sge i32 %1, %y
  ret i1 %r
}

log.current_optimized_program:
